	fwi, _ := fs.Sub(testdata, "testdata/valid/explicit_index")

	ss, err := SnapshotFromFS(zaptest.NewLogger(t), fwi)
	require.NoError(t, err)

	tfs := &FSIndexSuite{
		store: ss,
	}

	suite.Run(t, tfs)
}

type FSIndexSuite struct {
