					Property:     "foo",
					Operator:     "eq",
					Value:        "baz",
					Type:         flipt.ComparisonType_STRING_COMPARISON_TYPE,
					NamespaceKey: "sandbox",
				},
				{
					SegmentKey:   "segment1",
