	})

	require.NoError(t, err)

	res, err := s.store.ListRollouts(context.TODO(), storage.ListWithOptions(storage.NewResource(storage.DefaultNamespace, flag.Key)))

	// ensure rollouts are in correct order
	require.NoError(t, err)
	got := res.Results
	assert.NotNil(t, got)
